'use client';

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export const useStore = create(
  persist(
    (set, get) => ({
      members: [],
      transactions: [],

      totalDonation: 0,
      totalExpense: 0,
      netBalance: 0,

      // ------------------------------------------------------
      // নতুন লেনদেন যোগ করা
      // ------------------------------------------------------
      addTransaction: (tx) =>
        set((state) => {
          const newTx = {
            ...tx,
            id: Date.now().toString(),
            date: tx.date || new Date().toISOString().split('T')[0],
            amount: Number(tx.amount) || 0,
          };

          const updatedTransactions = [...state.transactions, newTx];

          // দানকারীকে অটো মেম্বার করা (avatar অটো জেনারেট করব না)
          let updatedMembers = [...state.members];

          if (newTx.type === 'donation' && newTx.donorName) {
            const donorNameLower = newTx.donorName.trim().toLowerCase();
            const existing = updatedMembers.find(
              (m) => m.name.trim().toLowerCase() === donorNameLower
            );

            if (!existing) {
              const newMember = {
                id: Date.now().toString() + '-auto',
                name: newTx.donorName.trim(),
                phone: '',
                address: '',
                avatar: '', // ← এখানে কোনো অটো avatar দিচ্ছি না (ফাঁকা)
                totalDonated: 0,
                totalReceived: 0,
                isAutoAdded: true,
              };
              updatedMembers = [...updatedMembers, newMember];
            }
          }

          // হিসাব আপডেট
          let donationSum = 0;
          let expenseSum = 0;

          updatedTransactions.forEach((t) => {
            const amt = Number(t.amount) || 0;
            if (t.type === 'donation') donationSum += amt;
            else if (t.type === 'expense') expenseSum += amt;
          });

          const net = donationSum - expenseSum;

          // মেম্বার totals রিসেট + নতুন হিসাব
          updatedMembers = updatedMembers.map((m) => ({
            ...m,
            totalDonated: 0,
            totalReceived: 0,
          }));

          updatedTransactions.forEach((t) => {
            if (t.type === 'donation') {
              const amt = Number(t.amount) || 0;

              if (t.donorName) {
                const donorLower = t.donorName.trim().toLowerCase();
                updatedMembers = updatedMembers.map((m) =>
                  m.name.trim().toLowerCase() === donorLower
                    ? { ...m, totalDonated: (m.totalDonated || 0) + amt }
                    : m
                );
              }

              if (t.receiverName) {
                const receiverLower = t.receiverName.trim().toLowerCase();
                updatedMembers = updatedMembers.map((m) =>
                  m.name.trim().toLowerCase() === receiverLower
                    ? { ...m, totalReceived: (m.totalReceived || 0) + amt }
                    : m
                );
              }
            }
          });

          return {
            transactions: updatedTransactions,
            members: updatedMembers,
            totalDonation: donationSum,
            totalExpense: expenseSum,
            netBalance: net < 0 ? 0 : net,
          };
        }),

      // ------------------------------------------------------
      // লেনদেন এডিট করা (updateTransaction)
      // ------------------------------------------------------
      updateTransaction: (id, updatedData) =>
        set((state) => {
          const updatedTransactions = state.transactions.map((t) =>
            t.id === id ? { ...t, ...updatedData, amount: Number(updatedData.amount) || t.amount } : t
          );

          let donationSum = 0;
          let expenseSum = 0;

          updatedTransactions.forEach((t) => {
            const amt = Number(t.amount) || 0;
            if (t.type === 'donation') donationSum += amt;
            else if (t.type === 'expense') expenseSum += amt;
          });

          const net = donationSum - expenseSum;

          // মেম্বার totals রিসেট + পুরোপুরি রিক্যালকুলেট
          let updatedMembers = state.members.map((m) => ({
            ...m,
            totalDonated: 0,
            totalReceived: 0,
          }));

          updatedTransactions.forEach((t) => {
            if (t.type === 'donation') {
              const amt = Number(t.amount) || 0;

              if (t.donorName) {
                const donorLower = t.donorName.trim().toLowerCase();
                updatedMembers = updatedMembers.map((m) =>
                  m.name.trim().toLowerCase() === donorLower
                    ? { ...m, totalDonated: (m.totalDonated || 0) + amt }
                    : m
                );
              }

              if (t.receiverName) {
                const receiverLower = t.receiverName.trim().toLowerCase();
                updatedMembers = updatedMembers.map((m) =>
                  m.name.trim().toLowerCase() === receiverLower
                    ? { ...m, totalReceived: (m.totalReceived || 0) + amt }
                    : m
                );
              }
            }
          });

          return {
            transactions: updatedTransactions,
            members: updatedMembers,
            totalDonation: donationSum,
            totalExpense: expenseSum,
            netBalance: net < 0 ? 0 : net,
          };
        }),

      // ------------------------------------------------------
      // লেনদেন ডিলিট (আগের মতো, কিন্তু হিসাব ঠিক রাখা)
      // ------------------------------------------------------
      deleteTransaction: (id) =>
        set((state) => {
          const updatedTransactions = state.transactions.filter((t) => t.id !== id);

          let donationSum = 0;
          let expenseSum = 0;

          updatedTransactions.forEach((t) => {
            const amt = Number(t.amount) || 0;
            if (t.type === 'donation') donationSum += amt;
            else if (t.type === 'expense') expenseSum += amt;
          });

          const net = donationSum - expenseSum;

          let updatedMembers = state.members.map((m) => ({
            ...m,
            totalDonated: 0,
            totalReceived: 0,
          }));

          updatedTransactions.forEach((t) => {
            if (t.type === 'donation') {
              const amt = Number(t.amount) || 0;

              if (t.donorName) {
                const donorLower = t.donorName.trim().toLowerCase();
                updatedMembers = updatedMembers.map((m) =>
                  m.name.trim().toLowerCase() === donorLower
                    ? { ...m, totalDonated: (m.totalDonated || 0) + amt }
                    : m
                );
              }

              if (t.receiverName) {
                const receiverLower = t.receiverName.trim().toLowerCase();
                updatedMembers = updatedMembers.map((m) =>
                  m.name.trim().toLowerCase() === receiverLower
                    ? { ...m, totalReceived: (m.totalReceived || 0) + amt }
                    : m
                );
              }
            }
          });

          return {
            transactions: updatedTransactions,
            members: updatedMembers,
            totalDonation: donationSum,
            totalExpense: expenseSum,
            netBalance: net < 0 ? 0 : net,
          };
        }),

      addMember: (data) =>
        set((state) => ({
          members: [
            ...state.members,
            {
              id: Date.now().toString(),
              name: data.name.trim(),
              phone: data.phone?.trim() || '',
              address: data.address?.trim() || '',
              avatar: data.avatar || '', // ← এখানেও অটো avatar না দিয়ে ফাঁকা রাখা
              totalDonated: 0,
              totalReceived: 0,
            },
          ],
        })),

      // ------------------------------------------------------
      // মেম্বার এডিট করা (avatar আপডেট করতে পারবে)
      // ------------------------------------------------------
      updateMember: (id, updates) =>
        set((state) => ({
          members: state.members.map((m) =>
            m.id === id ? { ...m, ...updates } : m
          ),
        })),
    }),
    {
      name: 'group-fund-v6', // নতুন ভার্সন → পুরানো ডেটা রিসেট হবে
    }
  )
);