'use client';
import Image from 'next/image';
import { useStore } from '../lib/store';
import { format } from 'date-fns';
import { bn } from 'date-fns/locale/bn';

export default function ReceiversList() {
  const { members, transactions } = useStore();

  const receiversWithDonations = members.map(m => {
    const received = transactions.filter(
      t => t.type === 'donation' && t.receiverName === m.name
    );
    return { ...m, received, totalReceived: received.reduce((sum, d) => sum + d.amount, 0) };
  }).filter(m => m.received.length > 0);

  if (receiversWithDonations.length === 0) {
    return (
      <div className="bg-white rounded-3xl p-12 text-center shadow-xl">
        <p className="text-2xl text-gray-600">এখনো কোনো গ্রহীতা নেই</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
      {receiversWithDonations.map(receiver => (
        <div key={receiver.id} className="bg-white rounded-3xl shadow-xl p-8 hover:shadow-2xl transition">
          <div className="flex items-center gap-6 mb-6">
            <div className="relative w-24 h-24 flex-shrink-0">
              <Image src={receiver.avatar} alt={receiver.name} fill className="rounded-full object-cover border-4 border-blue-300" />
            </div>
            <div>
              <h3 className="text-2xl font-bold text-blue-900">{receiver.name}</h3>
              <p className="text-gray-700">মোট পেয়েছে: {receiver.received.length} বার</p>
            </div>
          </div>

          <div className="space-y-4">
            {receiver.received.map(d => (
              <div key={d.id} className="bg-blue-50 p-5 rounded-2xl">
                <p className="font-semibold text-lg">← {d.donorName}</p>
                <p className="text-blue-700 font-bold text-xl mt-1">৳ {d.amount.toLocaleString('bn-BD')}</p>
                <p className="text-gray-700 mt-1">{d.reason || 'কারণ উল্লেখ নেই'}</p>
                <p className="text-sm text-gray-500 mt-2">
                  {format(new Date(d.date), 'dd MMM yyyy', { locale: bn })}
                </p>
              </div>
            ))}
          </div>

          <p className="text-right mt-6 font-bold text-blue-800 text-xl">
            মোট গ্রহণের পরিমাণ: ৳ {receiver.totalReceived.toLocaleString('bn-BD')}
          </p>
        </div>
      ))}
    </div>
  );
}